#[test]
fn i32_is_signed() {
    let proc_body = r#"
    # Stack: [a]
    exec.::intrinsics::i32::is_signed
    # Stack: [is_signed]
"#;
    test_i32_intrinsic(
        proc_body,
        NumericStrategy::<i32>::is_signed(),
        unary_i32op_input_to_stack,
        |a: &i32| Ok(vec![if *a < 0 { 1 } else { 0 }]),
    );
}

